import { ref } from 'vue'
import SvgLoader from '@/utils/SvgLoader'

export function useSvgLoader(config?: Record<string, { path: string; fallback?: string }>) {
  const svgLoader = SvgLoader.getInstance()
  const isReady = ref(false)

  // 注册配置
  if (config) {
    svgLoader.registerConfig(config)
  }

  // 获取图片路径
  const getIconPath = (iconName: string): string => {
    return svgLoader.getPath(iconName)
  }

  // 处理加载事件
  const handleImageLoad = (event: Event): void => {
    svgLoader.handleLoad(event)
  }

  // 处理错误事件
  const handleImageError = (event: Event): void => {
    svgLoader.handleError(event)
  }

  // 预加载图片
  const preloadImages = async (iconNames?: string[]): Promise<void> => {
    await svgLoader.preloadImages(iconNames)
    isReady.value = true
  }

  // 检查可用性
  const checkAvailability = (iconName: string): Promise<boolean> => {
    return svgLoader.checkAvailability(iconName)
  }

  // 获取加载状态
  const getLoadStatus = (iconName: string) => {
    return svgLoader.getLoadStatus(iconName)
  }

  return {
    isReady,
    getIconPath,
    handleImageLoad,
    handleImageError,
    preloadImages,
    checkAvailability,
    getLoadStatus
  }
}